import { describe, expect, it } from 'vitest';
import {
  solveMemeticHomophonic,
  type GenerationInfo,
} from '../src/memetic-cipher-solver';

// --- Test helpers --------------------------------------------------------
function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s;
  };
}

function buildRandomPermutation(seed: number): Map<string, string> {
  const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
  const next = lcg(seed);
  const shuffled = [...letters];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = next() % (i + 1);
    [shuffled[i], shuffled[j]] = [shuffled[j]!, shuffled[i]!];
  }
  const m = new Map<string, string>();
  for (let i = 0; i < 26; i++) m.set(letters[i]!, shuffled[i]!);
  return m;
}

function encrypt(plaintext: string, mapping: Map<string, string>): string {
  let out = '';
  for (const c of plaintext.toUpperCase()) {
    if (c >= 'A' && c <= 'Z') out += mapping.get(c) ?? c;
    else out += c;
  }
  return out;
}

// 60+ word English passage — Pride & Prejudice opening.
const PASSAGE = [
  'It is a truth universally acknowledged that a single man in possession',
  'of a good fortune must be in want of a wife. However little known the',
  'feelings or views of such a man may be on his first entering a',
  'neighbourhood, this truth is so well fixed in the minds of the',
  'surrounding families that he is considered the rightful property of',
  'some one or other of their daughters. My dear Mr. Bennet, said his',
  'lady to him one day, have you heard that Netherfield Park is let at',
  'last? Mr. Bennet replied that he had not. But it is, returned she.',
].join(' ');

describe('solveMemeticHomophonic', () => {
  it('recovers a simple monoalphabetic substitution on a long English passage', () => {
    const perm = buildRandomPermutation(12345);
    const ciphertext = encrypt(PASSAGE, perm);

    const result = solveMemeticHomophonic({
      ciphertext,
      populationSize: 12,
      generations: 15,
      saSwapsPerIndividual: 2000,
      seed: 0xCAFE,
    });

    // Honest scope: in 60s with population=12, generations=15, the memetic
    // search produces non-random output but typically doesn't fully crack.
    // Random permutation gives quadgram ≈ -10; solved English ≈ -3.
    // Asserting > -9 confirms the algorithm makes English-shaped progress
    // (the architectural claim) without overpromising on quality (a tuned
    // production solver with population=64, generations=200+ does much
    // better; that's a long-running attack, not a unit test).
    expect(result.score).toBeGreaterThan(-9.0);

    // History length matches generations.
    expect(result.scoreHistory.length).toBe(15);

    // scoreHistory should be non-decreasing within 5% fluctuation tolerance.
    for (let i = 1; i < result.scoreHistory.length; i++) {
      const prev = result.scoreHistory[i - 1]!;
      const cur = result.scoreHistory[i]!;
      const tolerance = Math.abs(prev) * 0.05;
      expect(cur).toBeGreaterThanOrEqual(prev - tolerance);
    }
  }, 60_000);

  it('returns the documented output shape', () => {
    const perm = buildRandomPermutation(777);
    const ciphertext = encrypt(PASSAGE, perm);

    const result = solveMemeticHomophonic({
      ciphertext,
      populationSize: 8,
      generations: 5,
      saSwapsPerIndividual: 500,
      seed: 0xBEEF,
    });

    // finalPopulationStats fields present.
    expect(result.finalPopulationStats).toHaveProperty('bestScore');
    expect(result.finalPopulationStats).toHaveProperty('worstScore');
    expect(result.finalPopulationStats).toHaveProperty('meanScore');

    // meanScore <= bestScore.
    expect(result.finalPopulationStats.meanScore).toBeLessThanOrEqual(
      result.finalPopulationStats.bestScore,
    );

    // scoreHistory length === args.generations.
    expect(result.scoreHistory.length).toBe(5);

    // result.score (best-ever) >= last-gen entry, since best-ever is
    // monotonically non-decreasing and the history records best-ever.
    const lastHistory = result.scoreHistory[result.scoreHistory.length - 1]!;
    expect(result.score).toBeGreaterThanOrEqual(lastHistory - 1e-9);
  }, 30_000);

  describe('validation', () => {
    it('throws RangeError on empty ciphertext', () => {
      expect(() =>
        solveMemeticHomophonic({ ciphertext: '' }),
      ).toThrow(RangeError);
    });

    it('throws RangeError when populationSize < 4', () => {
      expect(() =>
        solveMemeticHomophonic({
          ciphertext: 'HELLO WORLD',
          populationSize: 3,
        }),
      ).toThrow(RangeError);
    });

    it('throws RangeError when generations < 1', () => {
      expect(() =>
        solveMemeticHomophonic({
          ciphertext: 'HELLO WORLD',
          generations: 0,
        }),
      ).toThrow(RangeError);
    });

    it('throws RangeError when logisticR <= 3.5699 (out of chaotic regime)', () => {
      expect(() =>
        solveMemeticHomophonic({
          ciphertext: 'HELLO WORLD',
          logisticR: 3.5,
        }),
      ).toThrow(RangeError);
    });

    it('throws RangeError when logisticR > 4', () => {
      expect(() =>
        solveMemeticHomophonic({
          ciphertext: 'HELLO WORLD',
          logisticR: 4.1,
        }),
      ).toThrow(RangeError);
    });
  });

  it('is deterministic — same seed twice gives the same result', () => {
    const perm = buildRandomPermutation(42);
    const ciphertext = encrypt(PASSAGE, perm);

    const args = {
      ciphertext,
      populationSize: 6,
      generations: 4,
      saSwapsPerIndividual: 300,
      seed: 0xD00D,
    };

    const r1 = solveMemeticHomophonic(args);
    const r2 = solveMemeticHomophonic(args);

    expect(r1.score).toBe(r2.score);
    expect(r1.plaintext).toBe(r2.plaintext);
    expect(r1.scoreHistory).toEqual(r2.scoreHistory);
  }, 30_000);

  it('fires onGeneration callback once per generation with correct shape', () => {
    const perm = buildRandomPermutation(99);
    const ciphertext = encrypt(PASSAGE, perm);

    const events: GenerationInfo[] = [];
    const generations = 5;

    solveMemeticHomophonic({
      ciphertext,
      populationSize: 6,
      generations,
      saSwapsPerIndividual: 300,
      seed: 0xFEED,
      onGeneration: (info) => {
        events.push(info);
      },
    });

    expect(events.length).toBe(generations);

    for (let i = 0; i < events.length; i++) {
      const e = events[i]!;
      expect(e.generation).toBe(i);
      expect(typeof e.bestScore).toBe('number');
      expect(typeof e.worstScore).toBe('number');
      expect(typeof e.meanScore).toBe('number');
      expect(typeof e.diversity).toBe('number');
      expect(typeof e.mutationRate).toBe('number');
      expect(typeof e.bestPlaintext).toBe('string');
      expect(e.bestPlaintext.length).toBeGreaterThan(0);
    }
  }, 30_000);
});
